        // Use SAXBuilder to parse the XML content
        SAXBuilder saxBuilder = new SAXBuilder();

        try (StringReader reader = new StringReader(xmlContent)) {
            // Build the document
            Document document = saxBuilder.build(reader);

            // Get the root element
            Element rootElement = document.getRootElement();

            // Extract the text content of the <message> tag
            Element messageElement = rootElement.getChild("message");

            if (messageElement != null) {
                return messageElement.getTextTrim();
            }

            return null;
        } catch (JDOMException | IOException e) {
            // Return null if XML format is invalid or parsing fails
            return null;
        }
    }
